  ('pukao-e3452428-moex-00274', 'pukao-e3452428', 'pukao-e3452428-moex-112-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '地方自治團體為處理跨域合作事務而簽訂行政契約，如有其中一方未依約定履行應辦事項而產生 爭議時，應依下列何種程序處理？', '["先作成行政處分命其履行，拒不履行時移送行政執行機關進行強制執行", "聲請該管民事法院逕依強制執行法進行強制執行", "訴請該管行政法院判決後，依行政訴訟法規定聲請強制執行", "訴請民事法院判決後，聲請該管法院依行政訴訟法進行強制執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "e9f9351f595c", "answer_pdf_sha1": "1056724242c2", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "402", "s": "0310", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL)
